  UPDATE STB_B_USER_MNG
     SET USER_ID = #{userId}

      , USER_PSWD = #{userPswd}


     , USER_KOR_NM = #{userKorNm}


     , USER_ENG_NM = #{userEngNm}


     , MOBILE_NO = #{mobileNo}


     , EMAIL_ADDR = #{emailAddr}


     , ZIP_NO = #{zipNo}


     , HOME_ADDR = #{homeAddr}


     , HOME_ADDR_DTLS = #{homeAddrDtls}


     , BLON_NM = #{blonNm}


     , FAX_NO = #{faxNo}


     , JGRP_CD = #{jgrpCd}


     , JRNK_CD = #{jrnkCd}

WHERE USER_ID = #{userId}

/*  on.standard.system.user.updateAuthUserMng */
UPDATE STB_M_AUTH_USER_MNG
   SET USE_YN = 'Y'
    , AUTH_ID = #{userAuth}
WHERE AUTH_ID = #{preUserAuth}
  AND USER_ID = #{userId}
